package main

import "fmt"

// ---- Struct definition ----
type Player struct {
    Name    string
    Health  int
    Attack  int
    Defense int
    Level   int
}

// ---- Embedded struct ----
type Coordinates struct {
    X, Y int
}

type Enemy struct {
    Name       string
    Health     int
    Attack     int
    Position   Coordinates  // Embedded struct
    IsBoss     bool
}

func main() {
    // ---- Creating structs ----
    var p1 Player
    p2 := Player{Name: "Hero", Health: 100, Attack: 20, Defense: 10, Level: 1}
    p3 := Player{"Aragorn", 120, 25, 15, 5}

    fmt.Println("p1:", p1)
    fmt.Println("p2:", p2)
    fmt.Println("p3:", p3)

    // ---- Accessing fields ----
    fmt.Println("p2.Name:", p2.Name)
    fmt.Println("p2.Health:", p2.Health)

    // ---- Modifying fields ----
    p2.Health -= 20
    p2.Level = 2
    fmt.Println("After modification:", p2)

    // ---- Struct with embedded field ----
    enemy := Enemy{
        Name:   "Goblin",
        Health: 30,
        Attack: 8,
        Position: Coordinates{X: 5, Y: 10},
        IsBoss: false,
    }

    fmt.Println("Enemy:", enemy)
    fmt.Println("Enemy position:", enemy.Position.X, enemy.Position.Y)

    // ---- Anonymous struct ----
    item := struct {
        Name  string
        Value int
    }{
        Name:  "Sword",
        Value: 50,
    }
    fmt.Println("Item:", item)

    // ---- Struct pointers ----
    p4 := &p2
    p4.Health = 150  // Auto-dereference
    fmt.Println("p2 after pointer modification:", p2)

    // ---- Comparing structs ----
    p5 := Player{Name: "Hero", Health: 100, Attack: 20, Defense: 10, Level: 1}
    p6 := Player{Name: "Hero", Health: 100, Attack: 20, Defense: 10, Level: 1}
    p7 := Player{Name: "Aragorn", Health: 120, Attack: 25, Defense: 15, Level: 5}

    fmt.Println("p5 == p6:", p5 == p6)
    fmt.Println("p5 == p7:", p5 == p7)
}

