package main

import "fmt"

type Item struct {
    Name   string
    Value  int
    Weight int
}

func main() {
    item := Item{Name: "Sword", Value: 50, Weight: 3}
    fmt.Println("Item:", item)

    p := &item
    p.Name = "Iron Sword"
    fmt.Println("After modification:", item)
}
